# Generated by google (gemini-2.5-flash)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'BUILD_COMMAND', defaultValue: '', description: 'Shell command(s) for the build stage. Leave empty to skip this stage.')
        string(name: 'TEST_COMMAND', defaultValue: '', description: 'Shell command(s) for the test stage. Leave empty to skip this stage.')
        string(name: 'DEPLOY_COMMAND', defaultValue: '', description: 'Shell command(s) for the deployment stage. Leave empty to skip this stage.')
        booleanParam(name: 'FAIL_ON_EMPTY_COMMAND', defaultValue: false, description: 'If true, pipeline will fail if a stage is configured to run but its command is empty.')
    }

    stages {
        stage('Build') {
            when {
                expression {
                    def command = params.BUILD_COMMAND.trim()
                    if (command == '' && params.FAIL_ON_EMPTY_COMMAND) {
                        error('BUILD_COMMAND is empty, and FAIL_ON_EMPTY_COMMAND is true.')
                    }
                    return command != ''
                }
            }
            steps {
                echo "Executing custom build command..."
                sh params.BUILD_COMMAND
            }
        }

        stage('Test') {
            when {
                expression {
                    def command = params.TEST_COMMAND.trim()
                    if (command == '' && params.FAIL_ON_EMPTY_COMMAND) {
                        error('TEST_COMMAND is empty, and FAIL_ON_EMPTY_COMMAND is true.')
                    }
                    return command != ''
                }
            }
            steps {
                echo "Executing custom test command..."
                sh params.TEST_COMMAND
            }
        }

        stage('Deploy') {
            when {
                expression {
                    def command = params.DEPLOY_COMMAND.trim()
                    if (command == '' && params.FAIL_ON_EMPTY_COMMAND) {
                        error('DEPLOY_COMMAND is empty, and FAIL_ON_EMPTY_COMMAND is true.')
                    }
                    return command != ''
                }
            }
            steps {
                echo "Executing custom deployment command..."
                sh params.DEPLOY_COMMAND
            }
        }
    }

    post {
        always {
            echo 'Pipeline execution finished.'
        }
        success {
            echo 'Pipeline completed successfully.'
        }
        failure {
            echo 'Pipeline failed. Check logs for details.'
        }
        aborted {
            echo 'Pipeline was aborted.'
        }
    }
}